export default class DropdownSelect {
    constructor({
        element,
        data,
        type = "single",
        placeholder = "Select",
        preselected = [],
        searchable = false,
        key = "label",
        value = "value"
    }) {
        this.element = element;
        this.key = key;
        this.value = value;
        this.data = data ? this.normalizeData(data) : [];
        this.type = type;
        this.placeholder = placeholder;
        this.searchable = searchable;


        // Set preselected values
        this.selected = new Set(
            preselected && preselected.length > 0 && preselected[0] !== null
                ? preselected.flatMap(item => {
                    if (typeof item === 'string' && item.includes(',')) {
                        return item.split(',').map(val => val.trim());
                    }
                    return item;
                  })
                : []
        );

        this.highlightedIndex = 0;
        this.allOptionEls = [];
        this.eventListeners = {};

        this.prefix = "f";
        this.staticClass = {
            container: `${this.prefix}-dr-c`,
            menu: `${this.prefix}-dr-m`,
            search: `${this.prefix}-dr-se`,
            group: `${this.prefix}-dr-g`,
            option: `${this.prefix}-dr-o`,
        }
        this.render();
    }

    static currentOpenInstance = null;
    static globalClickListener = null;

    render() {
        this.element.classList.add(this.staticClass.container, "f--input");


        // Set value directly on the element
        if (this.selected.size > 0) {
            this.element.setAttribute('data-value', Array.from(this.selected).join(','));
        }

        // Use the element directly
        this.element.onclick = (e) => this.toggleMenu(e);

        this.updateSelectedText();

        document.addEventListener("keydown", (e) => this.handleKeydown(e));
    }

    toggleMenu(e) {
        if (!this.menu) {
            if (DropdownSelect.currentOpenInstance) {
                DropdownSelect.currentOpenInstance.closeMenu();
            }

            this.createMenu();
            DropdownSelect.currentOpenInstance = this;

            if (!DropdownSelect.globalClickListener) {
                DropdownSelect.globalClickListener = (e) => {
                    const instance = DropdownSelect.currentOpenInstance;
                    if (
                        instance &&
                        instance.menu &&
                        !instance.element.contains(e.target) &&
                        !instance.menu.contains(e.target)
                    ) {
                        instance.closeMenu();
                    }
                };
                document.addEventListener("click", DropdownSelect.globalClickListener);
            }
        } else {
            this.closeMenu();
        }
    }

    closeMenu() {
        if (this.menu) {
            this.menu.remove();
            this.menu = null;

            if (DropdownSelect.currentOpenInstance === this) {
                DropdownSelect.currentOpenInstance = null;
            }
        }
    }

    createMenu() {
        this.menu = document.createElement("div");
        this.menu.className = this.staticClass.menu;

        if (this.searchable) {
            const searchInput = document.createElement("input");
            searchInput.className = this.staticClass.search;
            searchInput.placeholder = "Search...";
            searchInput.autocomplete = "off";

            searchInput.addEventListener("input", (e) => {
                this.filterOptions(e.target.value.toLowerCase());
            });

            const searchInputWrapper = document.createElement("div");
            searchInputWrapper.appendChild(searchInput);
            this.menu.appendChild(searchInputWrapper);
        }

        this.optionContainer = document.createElement("div");
        this.menu.appendChild(this.optionContainer);

        // Append menu to document body and position it relative to the element
        document.body.appendChild(this.menu);
        this.positionMenu();

        this.buildOptions(this.data);
    }

    positionMenu() {
        const rect = this.element.getBoundingClientRect();
        this.menu.style.position = 'absolute';
        this.menu.style.top = `${rect.sb + window.scrollY}px`;
        this.menu.style.left = `${rect.left + window.scrollX}px`;
        this.menu.style.width = `${rect.width}px`;
        this.menu.style.zIndex = '999999999';
    }

    buildOptions(data) {
        this.optionContainer.innerHTML = "";
        this.allOptionEls = [];

        data.forEach((option) => {
            const optionEl = document.createElement("div");
            optionEl.className = this.staticClass.option;
            optionEl.tabIndex = 0;

            if (this.selected.has(option.value)) {
                optionEl.classList.add("selected");
            }

            const label = document.createElement("span");
            label.append(option.label);
            optionEl.appendChild(label);

            optionEl.onclick = (e) => {
                e.stopPropagation();
                this.toggleOption(option);
            };

            this.optionContainer.appendChild(optionEl);
            this.allOptionEls.push(optionEl);
        });

        this.updateSelectedText();
    }

    toggleOption(option) {
        if (this.type === "single") this.selected.clear();

        if (this.selected.has(option.value)) {
            this.selected.delete(option.value);
        } else {
            this.selected.add(option.value);
        }

        this.buildOptions(this.data);
        this.updateSelectedValue();

        if (this.type === "single") {
            this.closeMenu();
        }
    }

    filterOptions(query) {
        this.optionContainer.querySelectorAll(`.${this.staticClass.option}`).forEach((el) => {
            const label = el.innerText.toLowerCase();
            el.style.display = label.includes(query) ? "flex" : "none";
        });
    }

    updateSelectedText() {
        // Update the element's text content directly
        this.element.innerHTML = "";

        if (this.selected.size === 0) {
            this.element.innerText = this.placeholder;
            return;
        }

        const selectedItems = [];

        this.data.forEach((item) => {
            if (this.selected.has(item.value)) {
                selectedItems.push({
                    label: item.label,
                    value: item.value
                });
            }
        });

        selectedItems.forEach(({
            label
        }) => {
            const tag = document.createElement("span");
            tag.innerText = label;
            this.element.appendChild(tag);
        });
    }

    handleKeydown(e) {
        if (!this.menu) return;

        const visibleOptions = this.allOptionEls.filter(
            (el) => el.offsetParent !== null
        );
        if (visibleOptions.length === 0) return;

        if (e.key === "ArrowDown" || e.key === "Tab") {
            e.preventDefault();
            this.highlightedIndex =
                (this.highlightedIndex + 1) % visibleOptions.length;
            visibleOptions[this.highlightedIndex].focus();
        } else if (e.key === "ArrowUp") {
            e.preventDefault();
            this.highlightedIndex =
                (this.highlightedIndex - 1 + visibleOptions.length) %
                visibleOptions.length;
            visibleOptions[this.highlightedIndex].focus();
        } else if (e.key === "Enter") {
            e.preventDefault();
            visibleOptions[this.highlightedIndex]?.click();
        } else if (e.key === "Escape") {
            this.closeMenu();
        }
    }

    updateSelectedValue() {
        if (this.type === "single") {
            const selectedValues = Array.from(this.selected);
            this.element.setAttribute('data-value', selectedValues.length > 0 ? selectedValues[0] : '');
        } else {
            this.element.setAttribute('data-value', Array.from(this.selected).join(','));
        }

        // Dispatch a change event
        const event = new CustomEvent('change', {
            detail: Array.from(this.selected)
        });
        this.element.dispatchEvent(event);
    }

    normalizeData(data) {
        // Simply map the data to ensure it has the expected label/value format
        return data.map(item => ({
            label: item[this.key] || item.label,
            value: item[this.value] || item.value,
            imageUrl: item.imageUrl || null
        }));
    }

}
