import {
    controls,
    defaultValuesForm,
    icons
} from "../env.js";
import DOM from "./dom.js";
import Dragable from "./drag.js";
import Hooks from "./FormHooks.js";
import FormManager from "./FormManager.js";
import Marker from "./marker.js";
import {
    mousePosition
} from "./utils.js";


export default class ControlManager {
    constructor(state, api) {
        this.state = state;
        this.api = api;

        this.dom = new DOM();

        this.init();
        
    }


    init() {

        const elementRoot = this.dom.create({
            id: controls.init,
            inner: icons.root,
            isDraggable: true
        });
        const widgetWrapper = this.dom.create({ id: "widget-wrapper",});
        const controlsWrapper = this.dom.create({id: "controls-wrapper",});

        const inline = this.dom.create({
            id: "inline",
            inner: icons.inline
        });
        

        

        /* */
        this.dom.append(widgetWrapper, elementRoot);
        
        this.dom.append(document.body, widgetWrapper);

        new Dragable(widgetWrapper, 'widget', 'snap');

        if(this.state.user) {
            this.dom.append(widgetWrapper, controlsWrapper);
            this.dom.append(controlsWrapper, inline);
            this.markerInit();
        } else {
            const handleLogin = () => {
                console.log('widget clicked');
                const formManager = new FormManager(this.state);
                const loginForm = formManager.loginForm();
                loginForm.on("formLogin", async (data) => {
                    console.log(data);
                    const res = await this.api.loginUser(data.email, data.password);
                    
                    console.log(res);
                    if(res) {
                        this.state.setStage('init',`formLogin Hook>success`);
                        const apiRes = await this.api.initialize();
                        console.log(apiRes);
                        if(apiRes.isTasks) {
                            this.markerInit();
                        }
                        this.dom.off(elementRoot, 'click', handleLogin);
                            this.dom.append(widgetWrapper, controlsWrapper);
                            this.dom.append(controlsWrapper, inline);
                        loginForm.removeForm();
                        return res;
                    } else {
                        return false;
                    }
                });

                loginForm.on("formCancel", () => {
                    console.log('formCancel');
                    loginForm.removeForm();
                });
            };

            this.dom.on(elementRoot, 'click', handleLogin);
        }

        this.dom.on(inline, 'click', () => {

            const user = this.state.user;
            if (!user) {
                console.error('User not found');
                return;
            }

            if (this.state.stage === 'init' || this.state.stage === 'marker_click' ) {
                this.state.setStage('overlay', 'inline');
                this.#_createOverlay();
            } else {
                console.warn(`Stage is ${this.state.stage}. it's only allowed in init stage`);
            }
        });

    }

    
    markerInit() {
        console.log(this.state);
        const tasks = this.state.tasks;
        const user = this.state.user;

        if (!user) {
            console.error('User not found');
            return;
        }

        if (!tasks) {
            console.error('Tasks not found');
            return;
        }
        
        const marker = new Marker(this.state);  // Pass state here
        marker.loadMarkers();
        
        this.activeForm = null;

        marker.on('click', (taskId, isSecondClick) => {

            if (isSecondClick) {
                if (this.activeForm) {
                    this.activeForm.removeForm('marker_click');
                    this.activeForm = null;
                }
                return;
            }
            
            if (this.activeForm) {
                this.activeForm.removeForm('marker_click');
                this.activeForm = null;
            }
            
            // Create a new form for the clicked marker
            const formManager = new FormManager(this.state);
            const hooks = new Hooks(this.api);
            hooks.formCreate(formManager);
            hooks.formUpdate(formManager,()=>{
                marker.clearActive();
                marker.taskId = null;
                this.activeForm = null;
            });
            
            formManager.on(formManager.formEvents.formCancel, () => {
                marker.clearActive();
                marker.taskId = null;
                this.activeForm = null;
            });
            
            formManager.createForm({
                viewportInfo: null,
                id: "TaskFormUpdate",
                type: "update",
                defaultValues: parseInt(taskId),
                reason: 'marker_click'
            });
            
            this.activeForm = formManager;
        });
    }




    #createForm() {
        const formManager = new FormManager(this.state);
        const formHook = new Hooks(this.api);
        formHook.formCreate(formManager);
        formHook.formSubmit(formManager);
        formManager.createForm({
            viewportInfo: null,
            id: "TaskForm",
            type: "create",
            defaultValues: defaultValuesForm
        });
    }

    #_createOverlay() {
        const overlay = this.dom.create({ id: "f-overlay" });
        overlay.addEventListener('click', (e) => {

            const mousePos = mousePosition(e);
            this.state.setState("mousePos", mousePos, 'overlay');
            this.#removeOverlay();
            this.#createForm();
        });
        document.body.appendChild(overlay);
    }

    #removeOverlay() {
        const overlay = this.dom.getOne("#f-overlay");
        document.body.removeChild(overlay);
    }

    

}
