import DOM from "./dom.js";
import Dragable from "./drag.js";

export default class Marker {
    constructor(state){
     this.state = state;  // Add state
       this.tasks = this.state.tasks;
       this.user = this.state.user;
       this.taskId = null;
       this.previousTaskId = null;
       this.activeForm = null;
       this.dom = new DOM();
       
    }
    on(eventType, callback) {
        if (eventType === 'click') {
            const markers = this.dom.get('.mkr');
            markers.forEach(marker => {
                this.dom.on(marker, 'click', (e) => {
                    // Check stage before allowing marker clicks
                    if (this.state.stage === 'overlay' || 
                        this.state.stage === 'form_created') {
                        console.warn(`Stage is ${this.state.stage}. Marker clicks not allowed`);
                        return;
                    }

                    const taskId = this.dom.getAttr(marker, 'data-mkr-id');
                    if (this.taskId === taskId) {
                        this.clearActive();
                        this.taskId = null;
                        this.state.setStage('marker_double_click', 'marker-double-click');
                        callback(taskId, true); 
                    } else {
                        this.previousTaskId = this.taskId;
                        this.taskId = taskId;
                        
                        this.clearActive();
                        this.dom.addClass(marker, 'active');
                        
                        this.state.setStage('marker_click', 'marker-click');
                        callback(taskId, false);
                    }
                });
            });
        }
    }

    

    clearActive() {
        const markers = this.dom.get('.mkr');
        markers.forEach(marker => {
            this.dom.removeClass(marker, 'active');
        });
    }

    createMarker(index,task){

        const marker = this.dom.create({
            id: "marker",
            className: "mkr",
            inner: index,
            attributes: {
                'data-mkr-id': task.id
            }
        });

        // new Dragable(marker,null,'free',{
        //         x: task.screeninfo.document.x,
        //         y: task.screeninfo.document.y
        //     });

        this.dom.style(marker,{
            position: "absolute",
            top: task.screeninfo.document.y + "px",
            left: task.screeninfo.document.x + "px",
        });

        document.body.appendChild(marker);
        return marker;
    }
    loadMarkers(){
        this.tasks.forEach((task, index) => {
            this.createMarker(index+1,task);
        });
    }


   

}
