import Storage from './storage.js';

export default class Dragable {
    constructor(element, storageKey = null, type = 'free' , initialPosition = {x: 0, y: 0}) {
        if (!element) throw new Error('Element not found');
        this.element = element;
        this.storageKey = storageKey;
        this.type = type; // 'free' or 'snap'
        this.isDragging = false;
        this.offsetX = initialPosition.x;
        this.offsetY = initialPosition.y;
        this.storage = new Storage();

        this.init();
    }

    init() {
        this.element.style.position = 'absolute';
        this.element.style.left = `${this.offsetX}px`;
        this.element.style.top = `${this.offsetY}px`;
        
        this.loadSavedPosition();
        this.setupDraggable();
        this.attachEventListeners();
    }

    loadSavedPosition() {
        if (!this.storageKey) return;
        try {
            const savedPosition = this.storage.getItem(this.storageKey) || { x: 0, y: 0 };
            const windowHeight = window.innerHeight;
            const adjustedY = Math.min(Math.max(0, savedPosition.y), windowHeight - 100);
            
            if (this.type === 'free' && typeof savedPosition.x === 'number' && savedPosition.x > 1) {
                // In free mode with a specific x position (greater than 1 to distinguish from snap mode's 0/1)
                this.updatePosition(null, adjustedY, savedPosition.x);
            } else {
                // In snap mode or default positioning
                const isLeft = savedPosition.x === 0;
                this.updateAlignment(isLeft);
                this.updatePosition(isLeft, adjustedY);
            }
        } catch (e) {
            console.error('Error loading position:', e);
        }
    }

    setupDraggable() {
        this.element.setAttribute('draggable', 'true');
        this.element.style.cursor = 'move';
    }

    attachEventListeners() {
        this.element.addEventListener('mousedown', this.handleMouseDown.bind(this));
        document.addEventListener('mousemove', this.handleMouseMove.bind(this));
        document.addEventListener('mouseup', this.handleMouseUp.bind(this));
        document.addEventListener('mouseleave', this.handleMouseLeave.bind(this));
    }

    handleMouseDown(e) {
        // Only initiate drag if the click is directly on the element or its parent,
        // not on child elements
        if (e.button !== 0 || e.target !== this.element && !this.element.contains(e.target)) return;
        
        // Check if the click is on a child element that should be excluded from dragging
        if (e.target !== this.element && e.target.closest('button, input, select, a, [data-no-drag]')) {
            return;
        }
        
        this.isDragging = true;
        this.element.classList.add('dragging');
        this.element.style.transition = 'none';
        
        const rect = this.element.getBoundingClientRect();
        this.offsetX = e.clientX - rect.left;
        this.offsetY = e.clientY - rect.top;
        
        e.preventDefault();
    }

    handleMouseMove(e) {
        if (!this.isDragging) return;
        
        // Calculate new position
        let newX = e.clientX - this.offsetX;
        let newY = e.clientY - this.offsetY;
        
        // Constrain to window boundaries
        const windowWidth = window.innerWidth;
        const windowHeight = window.innerHeight;
        const elementWidth = this.element.offsetWidth;
        const elementHeight = this.element.offsetHeight;
        
        // Prevent negative positions and exceeding window boundaries
        newX = Math.max(0, Math.min(newX, windowWidth - elementWidth));
        newY = Math.max(0, Math.min(newY, windowHeight - elementHeight));
        
        // Apply new position
        this.element.style.left = `${newX}px`;
        this.element.style.top = `${newY}px`;
        this.element.style.right = 'auto';
        this.element.style.sb = 'auto';
    }

    handleMouseUp() {
        if (!this.isDragging) return;
        
        this.isDragging = false;
        this.element.classList.remove('dragging');
        
        const rect = this.element.getBoundingClientRect();
        const windowWidth = window.innerWidth;
        const windowHeight = window.innerHeight;
        
        // Ensure position is within bounds
        const adjustedX = Math.max(0, rect.left);
        const adjustedY = Math.max(0, Math.min(rect.top, windowHeight - rect.height));
        const isLeft = adjustedX < windowWidth / 2;
        
        if (this.type === 'snap') {
            // In snap mode, always snap to left or right edge
            this.snapToEdge(isLeft, adjustedY);
            this.savePosition(isLeft, adjustedY);
        } else if (this.type === 'free') {
            // In free mode, stay where dropped but ensure within bounds
            this.element.style.left = `${adjustedX}px`;
            this.element.style.top = `${adjustedY}px`;
            this.savePosition(isLeft, adjustedY, adjustedX);
        }
    }

    handleMouseLeave() {
        if (this.isDragging) {
            this.isDragging = false;
            this.element.classList.remove('dragging');
            
            if (this.type === 'snap') {
                this.element.style.transition = 'all 0.2s ease';
            }
        }
    }

    updateAlignment(isLeft) {
        this.element.classList.toggle('align-left', isLeft);
        this.element.classList.toggle('align-right', !isLeft);
    }

    updatePosition(isLeft, y, x = null) {
        if (this.type === 'free' && x !== null) {
            // In free mode with specific x position
            this.element.style.left = `${x}px`;
            this.element.style.right = 'auto';
            this.element.style.top = `${y}px`;
        } else {
            // In snap mode or default positioning
            this.element.style.left = isLeft ? '0px' : 'auto';
            this.element.style.right = !isLeft ? '0px' : 'auto';
            this.element.style.top = `${y}px`;
        }
    }

    snapToEdge(isLeft, y) {
        // Reset transition first
        this.element.style.transition = 'none';
        
        // Apply position
        this.updatePosition(isLeft, y);
        this.updateAlignment(isLeft);
        
        // Force reflow
        void this.element.offsetHeight;
        
        // Add transition for smooth animation
        this.element.style.transition = 'left 0.2s ease, right 0.2s ease, top 0.2s ease';
    }

    savePosition(isLeft, y, x = null) {
        if (!this.storageKey) return;
        try {
            if (this.type === 'free' && x !== null) {
                // In free mode, save actual x position
                this.storage.setItem(this.storageKey, { x: x, y });
            } else {
                // In snap mode, save 0 for left, 1 for right
                this.storage.setItem(this.storageKey, { x: isLeft ? 0 : 1, y });
            }
        } catch (e) {
            console.error('Error saving position:', e);
        }
    }

    getPosition() {
        const rect = this.element.getBoundingClientRect();
        return {
            x: rect.left,
            y: rect.top
        };
    }

    // add custom evenet where user mouse up then retun get position value
    on(event, callback) {
        if (event === 'mouseup') {
            this.element.addEventListener('mouseup', () => {
                callback(this.getPosition());
            });
        }
    }
}
